void AMyCharacter::TakeDamage(float Damage) {
    if (HasAuthority()) {
        // SERVER: apply actual damage
        Health -= Damage;  // This replicates to clients
        if (Health <= 0) Die();
    }
    // ALL MACHINES: play hit effect (cosmetic)
    PlayHitAnimation();
}
